// ❌ BAD - return type forces caller to handle a separate null check
public decimal ParsePaymentAmount(string input)
{
    return decimal.Parse(input); // throws FormatException on bad input
}

// ✅ GOOD - out pattern gives both success flag and result in one call
public bool TryParsePaymentAmount(string input, out decimal amount)
{
    return decimal.TryParse(input, out amount);
}

// in - avoids copying a large pricing matrix struct
public decimal CalculateDiscount(in PricingMatrix matrix, int tier)
    => matrix.Rows[tier] * 0.1m; // matrix is read-only, no 512-byte copy

// ❌ BAD - no annotation, NullReferenceException waits at runtime
public string GetCustomerEmail(int id)
{
    var customer = _db.Customers.Find(id);
    return customer.Email; // throws if customer is null
}

// ✅ GOOD - NRT makes the nullable contract explicit at compile time
public string? GetCustomerEmail(int id)
{
    var customer = _db.Customers.Find(id);
    return customer?.Email; // null propagates safely
}

// Caller is warned to check before use
string? email = GetCustomerEmail(42);
if (email is not null)
    SendWelcome(email); // compiler knows email is non-null here

// ❌ BAD - block bodies for trivial one-liners add visual noise
public class ShippingAddress
{
    public string Street { get; }
    public string City { get; }
    public ShippingAddress(string street, string city) { Street = street; City = city; }
    public override string ToString() { return $"{Street}, {City}"; }
}

// ✅ GOOD - expression-bodied members cut the noise
public class ShippingAddress
{
    public string Street { get; }
    public string City { get; }
    public ShippingAddress(string street, string city) => (Street, City) = (street, city);
    public string Display => $"{Street}, {City}";
    public override string ToString() => Display;
}

// ❌ BAD - trying to assign generic types without variance - compile error
IEnumerable<Dog> dogs = new List<Dog> { new Dog() };
// IEnumerable<Animal> animals = dogs; // error without covariance

// ✅ GOOD - IEnumerable<out T> is covariant so this compiles
IEnumerable<Animal> animals = dogs; // valid - T is out in IEnumerable<T>

// Contravariance - Action<in T>
Action<Animal> feedAnimal = a => Console.WriteLine($"Feed {a.Name}");
Action<Dog> feedDog = feedAnimal; // valid - a handler for Animal works for Dog too
feedDog(new Dog { Name = "Rex" });

// ❌ BAD - using dynamic in application code hides errors until runtime
dynamic order = GetOrderFromExternalApi();
Console.WriteLine(order.CustomerNmae); // typo - crashes at runtime, not compile time

// ✅ GOOD - COM interop is the legitimate case for dynamic
dynamic excelApp = Activator.CreateInstance(Type.GetTypeFromProgID("Excel.Application"));
excelApp.Visible = true; // COM API is not statically typed
excelApp.Workbooks.Add();

