// ❌ BAD - injecting IOptionsSnapshot into a singleton service = captive dependency
public class NotificationSingleton
{
    public NotificationSingleton(IOptionsSnapshot<SmtpOptions> opts) { } // wrong!
}

// ✅ GOOD - IOptionsMonitor in singleton; IOptionsSnapshot in scoped service
public class EmailSender // registered as scoped
{
    private readonly SmtpOptions _opts;
    public EmailSender(IOptionsSnapshot<SmtpOptions> opts) => _opts = opts.Value;
}

public class RateLimiter // registered as singleton
{
    private readonly IOptionsMonitor<RateLimitOptions> _monitor;
    public RateLimiter(IOptionsMonitor<RateLimitOptions> monitor) => _monitor = monitor;
    public int GetLimit() => _monitor.CurrentValue.RequestsPerMinute;
}

// ❌ BAD - hand-written code mixed into a generated file, overwritten on next scaffold
// CustomerEntity.cs (EF generated + your code mixed in)
public class CustomerEntity
{
    public int Id { get; set; }      // generated
    public string FullName => ...;   // your code - lost on next scaffold
}

// ✅ GOOD - keep generated and hand-written in separate partial files
// CustomerEntity.Generated.cs (do not edit)
public partial class CustomerEntity { public int Id { get; set; } }

// CustomerEntity.cs (your code - never overwritten)
public partial class CustomerEntity
{
    public string FullName => $"{FirstName} {LastName}";
    public bool IsVerified => VerifiedAt.HasValue;
}

// ❌ BAD - throw ex resets the stack trace, hiding the real error location
try { ProcessPayment(order); }
catch (PaymentException ex)
{
    _logger.LogError(ex, "Payment failed");
    throw ex; // stack trace now points here, not to the real failure line
}

// ✅ GOOD - bare throw preserves the original stack trace
try { ProcessPayment(order); }
catch (PaymentException ex)
{
    _logger.LogError(ex, "Payment failed for order {OrderId}", order.Id);
    throw; // original stack trace intact
}

// ✅ ALSO GOOD - wrap with context when caller needs more info
catch (DbException ex)
{
    throw new OrderPersistenceException($"Failed to save order {order.Id}", ex);
}

// ❌ BAD - public const is inlined into callers; changing it is a silent breaking change
public const int MaxOrderLines = 50;
// Caller assembly sees 50 baked in; updating to 100 here requires recompiling callers

// ✅ GOOD - static readonly is read at runtime so callers always get the current value
public static readonly int MaxOrderLines = 50;
public static readonly TimeSpan SessionTimeout = TimeSpan.FromMinutes(30);

// readonly - per-instance, set in constructor
public class Order
{
    public readonly Guid OrderId;
    public Order() => OrderId = Guid.NewGuid();
}
